{"tool":"newFileCreated","path":"frontend/src/components/Sidebar.jsx","content":"import React, { useState, useEffect } from 'react';
import { Activity, FileText, Wrench, Shield, Users, Calendar, LogOut, UserPlus, Clock, Package } from 'lucide-react';

const Sidebar = ({ user, activeTab, onTabChange, onLogout }) => {
  const [restingToday, setRestingToday] = useState([]);
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const fetchResting = async () => {
      try {
        const token = localStorage.getItem('token');
        const res = await fetch(`http://${window.location.hostname}:8000/rest-days/today`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        if (res.ok) {
          const data = await res.json();
          setRestingToday(data);
        }
      } catch (e) {}
    };
    fetchResting();
    const interval = setInterval(fetchResting, 5000);
    const h = () => fetchResting();
    window.addEventListener('app-refresh', h);
    return () => { clearInterval(interval); window.removeEventListener('app-refresh', h); };
  }, []);

  const formatDate = (d) => {
    const days = ['Yakshanba', 'Dushanba', 'Seshanba', 'Chorshanba', 'Payshanba', 'Juma', 'Shanba'];
    const months = ['Yanvar', 'Fevral', 'Mart', 'Aprel', 'May', 'Iyun', 'Iyul', 'Avgust', 'Sentabr', 'Oktabr', 'Noyabr', 'Dekabr'];
    return `${d.getDate()} ${months[d.getMonth()]}, ${days[d.getDay()]}`;
  };
  const formatTime = (d) => d.toLocaleTimeString('uz-UZ', { hour: '2-digit', minute: '2-digit', second: '2-digit' });

  const tabs = [
    { id: 'run', label: 'Stanoklar', icon: Activity, roles: ['ADMIN', 'MASTER', 'NAZORATCHI', 'MECHANIC', 'ELECTRIC', 'UZLAVYAZ'] },
    { id: 'mechanic', label: 'Mexanik', icon: Wrench, roles: ['ADMIN', 'MASTER', 'NAZORATCHI', 'MECHANIC', 'ELECTRIC', 'UZLAVYAZ'] },
    { id: 'report', label: 'Hisobot', icon: FileText, roles: ['ADMIN', 'NAZORATCHI'] },
    { id: 'master', label: "Operator", icon: UserPlus, roles: ['ADMIN', 'MASTER'] },
    { id: 'nazoratchi', label: 'Dam kunlar', icon: Calendar, roles: ['ADMIN', 'NAZORATCHI'] },
    { id: 'asnova', label: 'Asnova Qoldigi', icon: Package, roles: ['ADMIN', 'MASTER', 'NAZORATCHI', 'UZLAVYAZ'] },
    { id: 'users', label: 'Foydalanuvchilar', icon: Users, roles: ['ADMIN'] },
    { id: 'admin', label: 'Sozlamalar', icon: Shield, roles: ['ADMIN'] },
  ];

  const visibleTabs = tabs.filter(t => t.roles.includes(user?.role));

  return (
    <>
      {/* ═══ DESKTOP SIDEBAR ═══ */}
      <div className="sidebar-desktop">
        <div style={{ marginBottom: '1.5rem' }}>
          <h1 style={{ fontSize: '1.4rem', fontWeight: 900, color: 'var(--primary)', margin: 0, letterSpacing: '-1px' }}>
            SMART ESP32
          </h1>
          <p style={{ fontSize: '0.65rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px' }}>
            Industrial Monitor v3.0
          </p>
        </div>

        {/* Date & Time */}
        <div style={{
          background: 'rgba(0,210,255,0.08)', border: '1px solid rgba(0,210,255,0.2)',
          borderRadius: '12px', padding: '10px 14px', marginBottom: '1rem'
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px' }}>
            <Clock size={14} color="#00d2ff" />
            <span style={{ fontSize: '1.1rem', fontWeight: 800, color: '#00d2ff', fontFamily: 'monospace' }}>
              {formatTime(currentTime)}
            </span>
          </div>
          <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', fontWeight: 600 }}>
            {formatDate(currentTime)}
          </div>
        </div>

        {restingToday.length > 0 && (
          <div style={{
            background: 'rgba(251, 191, 36, 0.1)',
            border: '1px solid rgba(251, 191, 36, 0.3)',
            borderRadius: '12px',
            padding: '0.75rem',
            marginBottom: '1rem'
          }}>
            <div style={{ fontSize: '0.65rem', fontWeight: 700, color: '#fbbf24', textTransform: 'uppercase', marginBottom: '4px' }}>
              Bugun dam olganlar:
            </div>
            <div style={{ fontSize: '0.8rem', color: '#fde68a', fontWeight: 600 }}>
              {restingToday.map(r => r.operator_name).join(', ')}
            </div>
          </div>
        )}

        <nav style={{ display: 'flex', flexDirection: 'column', gap: '4px', flex: 1 }}>
          {visibleTabs.map(tab => {
            const Icon = tab.icon;
            return (
              <button
                key={tab.id}
                onClick={() => onTabChange(tab.id)}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '10px',
                  padding: '10px 14px',
                  borderRadius: '10px',
                  border: 'none',
                  cursor: 'pointer',
                  fontSize: '0.85rem',
                  fontWeight: 600,
                  background: activeTab === tab.id ? 'rgba(0, 210, 255, 0.15)' : 'transparent',
                  color: activeTab === tab.id ? 'var(--primary)' : 'var(--text-muted)',
                  transition: 'all 0.2s',
                  textAlign: 'left',
                }}
              >
                <Icon size={18} />
                {tab.label}
              </button>
            );
          })}
        </nav>

        <div style={{ padding: '1rem', background: 'rgba(255,255,255,0.03)', borderRadius: '16px', marginTop: '1rem' }}>
          <div style={{ marginBottom: '0.75rem' }}>
            <p style={{ margin: 0, fontSize: '0.9rem', fontWeight: 600 }}>{user?.full_name}</p>
            <p style={{ margin: 0, fontSize: '0.7rem', color: 'var(--text-muted)' }}>{user?.role}</p>
          </div>
          <button
            onClick={onLogout}
            style={{
              width: '100%',
              padding: '8px',
              fontSize: '0.8rem',
              background: '#ef444422',
              color: '#ef4444',
              border: '1px solid #ef444444',
              borderRadius: '8px',
              cursor: 'pointer',
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '6px'
            }}
          >
            <LogOut size={14} /> Chiqish
          </button>
        </div>
      </div>

      {/* ═══ MOBILE BOTTOM BAR ═══ */}
      <div className="mobile-bottom-bar">
        <div className="mobile-bottom-bar-inner">
          {visibleTabs.map(tab => {
            const Icon = tab.icon;
            const isActive = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                className={`mobile-tab-btn ${isActive ? 'active' : ''}`}
                onClick={() => onTabChange(tab.id)}
              >
                <div className="mobile-tab-icon-wrap">
                  <Icon size={20} strokeWidth={isActive ? 2.5 : 1.8} />
                </div>
                <span className="mobile-tab-label">{tab.label}</span>
              </button>
            );
          })}
          <button className="mobile-tab-btn logout-btn" onClick={onLogout}>
            <div className="mobile-tab-icon-wrap">
              <LogOut size={20} strokeWidth={1.8} />
            </div>
            <span className="mobile-tab-label">Chiqish</span>
          </button>
        </div>
      </div>
    </>
  );
};

export default Sidebar;","isOutsideWorkspace":false,"isProtected":false,"id":"unified_1775048442769_write_0"}

{"tool":"newFileCreated","path":"frontend/src/components/AsnovaPanel.jsx","content":"import React, { useState, useEffect } from 'react';
import { Package, Download, RefreshCw } from 'lucide-react';

const AsnovaPanel = ({ user }) => {
  const token = localStorage.getItem('token');
  const API = `http://${window.location.hostname}:8000`;
  const [machines, setMachines] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchMachines();
    const interval = setInterval(fetchMachines, 5000);
    return () => clearInterval(interval);
  }, []);

  const fetchMachines = async () => {
    try {
      const res = await fetch(`${API}/machines`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setMachines(data);
      }
    } catch (e) {}
  };

  const getAsnovaRemaining = (m) => {
    return Math.max(0, (m.initial_asnova_length || 0) - ((m.current_total_meters || 0) - (m.meters_at_fill || 0)));
  };

  const totalAsnova = machines.reduce((sum, m) => sum + getAsnovaRemaining(m), 0);

  const downloadPDF = async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API}/reports/asnova-pdf`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ machines: machines.map(m => ({ id: m.id, remaining: getAsnovaRemaining(m) })) })
      });
      if (res.ok) {
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `asnova_qoldigi_${new Date().toISOString().split('T')[0]}.pdf`;
        a.click();
        window.URL.revokeObjectURL(url);
      }
    } catch (e) {}
    setLoading(false);
  };

  const downloadExcel = async () => {
    setLoading(true);
    try {
      const res = await fetch(`${API}/reports/asnova-excel`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ machines: machines.map(m => ({ id: m.id, remaining: getAsnovaRemaining(m) })) })
      });
      if (res.ok) {
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `asnova_qoldigi_${new Date().toISOString().split('T')[0]}.xlsx`;
        a.click();
        window.URL.revokeObjectURL(url);
      }
    } catch (e) {}
    setLoading(false);
  };

  const getStatusColor = (m) => {
    const remaining = getAsnovaRemaining(m);
    if (remaining <= 0) return '#ff3131';
    if (remaining < 500) return '#f59e0b';
    return '#22c55e';
  };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '12px' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>
          <Package size={24} style={{ marginRight: '8px', verticalAlign: 'middle' }} />
          Asnova Qoldigi
        </h2>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button onClick={fetchMachines} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
            background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)', border: '1px solid var(--panel-border)',
            borderRadius: '10px', cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem'
          }}>
            <RefreshCw size={16} /> Yangilash
          </button>
          <button onClick={downloadExcel} disabled={loading} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
            background: 'rgba(34,197,94,0.15)', color: '#22c55e', border: 'none',
            borderRadius: '10px', cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem'
          }}>
            <Download size={16} /> Excel
          </button>
          <button onClick={downloadPDF} disabled={loading} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
            background: 'rgba(0,210,255,0.15)', color: '#00d2ff', border: 'none',
            borderRadius: '10px', cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem'
          }}>
            <Download size={16} /> PDF
          </button>
        </div>
      </div>

      {/* Total Summary */}
      <div style={{
        background: 'linear-gradient(135deg, rgba(0,210,255,0.1), rgba(168,85,247,0.1))',
        border: '1px solid rgba(0,210,255,0.3)', borderRadius: '16px',
        padding: '1.5rem', marginBottom: '1.5rem', textAlign: 'center'
      }}>
        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '4px' }}>
          Jami Asnova Qoldigi
        </div>
        <div style={{ fontSize: '2.5rem', fontWeight: 900, color: '#00d2ff', fontFamily: 'monospace' }}>
          {totalAsnova.toFixed(1)} <span style={{ fontSize: '1rem', color: 'var(--text-muted)' }}>m</span>
        </div>
      </div>

      {/* Machine Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))', gap: '10px' }}>
        {machines.map(m => {
          const remaining = getAsnovaRemaining(m);
          const color = getStatusColor(m);
          const isOnline = m.status !== 'OFFLINE';
          return (
            <div key={m.id} style={{
              background: 'var(--card)', border: `1px solid ${color}33`,
              borderRadius: '12px', padding: '12px', textAlign: 'center',
              transition: '0.2s'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px', marginBottom: '6px' }}>
                <div style={{
                  width: '8px', height: '8px', borderRadius: '50%',
                  background: isOnline ? '#22c55e' : '#ff3131',
                  boxShadow: `0 0 6px ${isOnline ? '#22c55e' : '#ff3131'}`
                }} />
                <span style={{ fontWeight: 800, fontSize: '0.9rem' }}>{m.id}</span>
              </div>
              <div style={{ fontSize: '1.2rem', fontWeight: 900, color, fontFamily: 'monospace' }}>
                {remaining.toFixed(1)}
              </div>
              <div style={{ fontSize: '0.6rem', color: 'var(--text-muted)', fontWeight: 600 }}>metr</div>
            </div>
          );
        })}
      </div>

      {loading && (
        <div className="modal-overlay">
          <div style={{ color: 'var(--primary)', fontSize: '1.2rem', fontWeight: 800 }}>
            Yuklanmoqda...
          </div>
        </div>
      )}
    </div>
  );
};

export default AsnovaPanel;","isOutsideWorkspace":false,"isProtected":false,"id":"unified_1775048528950_write_0","diff":"@@ -0,0 +1,169 @@
